  "pattern": {
    "name": "sub_of_masked_const_minus_x_to_affine_masked_x",
    "summary": "Match an outer subtraction with a constant LHS whose RHS is a one-use bitwise-and of an inner subtraction from a constant: C - ((C3 - X) & C2). Under the known-safe conditions, rewrite it to (C - (C2 & C3)) + (X & C2), eliminating the nested subtract-under-mask and exposing a simpler affine form in X.",
    "match": {
      "root": "%r = sub Ty C, %and",
      "and": "%and = and Ty %sub, C2",
      "inner_sub": "%sub = sub [nuw optional] Ty C3, %x",
      "requirements": [
        "C, C2, C3 are integer constants of the same type Ty",
        "%and has one use",
        "Either the inner sub has nuw, or C2 is a negated power-of-2 mask",
        "(C3 - ((C2 & C3) - 1)) is a power of 2",
        "((C2 + C3) & ((C2 & C3) - 1)) == ((C2 & C3) - 1)"
      ]
    },
    "rewrite": {
      "result": "%r.new = add Ty (C - (C2 & C3)), (%x & C2)",
      "notes": [
        "The add may canonicalize to sub with a negative constant or preserve add depending on target/canonical form",
        "The masked term may remain as an and of X with C2",
        "Works for scalars and fixed-width vectors with splat constants"
      ]
    },
    "intuition": "Masking low bits after computing (C3 - X) makes those bits depend only on X modulo the masked region. When the arithmetic/mask constraints hold, the masked value is equivalent to a constant offset plus (X & C2), so the whole expression becomes an affine constant-plus-masked-X form.",
    "implementation_notes": [
      "Natural home is InstCombine::visitSub",
      "Use m_Sub(m_Constant(C), m_OneUse(m_And(m_Sub(m_Constant(C3), m_Value(X)), m_Constant(C2)))) with flags checked on the inner sub",
      "Support scalar integers and vectors with splat constants",
      "Preserve poison/flag correctness: legality route is either nuw on the inner sub or the negated-power-of-2-mask route"
    ]
  },
